  ipcMain.removeHandler('save-scraped-stories');
  ipcMain.handle('save-scraped-stories', async (event, args) => {
    const db = new ImparcialDb();
    const stories = args[0] as any[];
    console.log(`save-scraped-stories - stories: ${stories.length}`)
    const newsScrapingState = args[1] as ScrapingJobState;
    let scrapedDate = "";
    let scrapingJobId = 0;
    console.log({newsScrapingState});
    if(newsScrapingState && newsScrapingState.ScrapingJobId > 0) {
      scrapingJobId = newsScrapingState.ScrapingJobId;
      scrapedDate = newsScrapingState.ScrapingDate;
    }
    else {
      // query last scraping job for news
      const scrapingJob = await db.get("SELECT ScrapeJobId, JobStartDate from ScrapingJob WHERE JobType = 'NEWS_SCRAPER' AND Processed = 0 AND Status = 'NOT_PROCESSED' LIMIT 1;");
      if(scrapingJob) {
        scrapingJobId = scrapingJob.ScrapeJobId;
        scrapedDate = scrapingJob.JobStartDate;
      }
      else {
        throw new Error("No scraping job news found for news scraper");
      }
    }
    const addStory = "INSERT INTO story (Title, Description, Uri, SourceTypeId, Media, ScrapedDate, Hash, ArticleText, CanSummarize) VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?);"
    const insertNotification = "INSERT INTO NotificationJob (ObjectQty, Data, JobDate, JobType, Processed, Status) VALUES (?, ?, ?, ?, ?, ?);"
    const lookupStory = "SELECT count(StoryId) as count FROM Story where Hash = ?;"
    const updateScrapingJobQuery = "UPDATE ScrapingJob SET ObjectQty = ?, Processed = ?, Status = ?, JobEndDate = ? WHERE ScrapeJobId = ?;"
    // Add stories to database
    let filteredStories: any[] = [];
    // check if stories already exist
    for(let i=0; i < stories.length; i++) {
        const story = await db.get(lookupStory, [stories[i].hash]);
        if(story && story.count == 0) {
            // console.log("try to add to filtered list")
            // add story to filtered list
            const foundIndex = filteredStories.findIndex((filtered) => filtered.hash == stories[i].hash);
            // console.log({foundIndex});
            if(foundIndex == -1)
                filteredStories.push(stories[i]);
        }
    }

    console.log(`save-scraped-stories - filteredStories: ${filteredStories.length}`);

    let insertComplete = false;
    let insertAttempts = 0
    let maxInsertAttempts = 3
    while (insertAttempts < maxInsertAttempts && !insertComplete) {
        insertAttempts++;
        try {
          // add stories
          for(let ii=0; ii < filteredStories.length; ii++) {
            const _story = filteredStories[ii];
            await db.run(addStory, [_story.title, _story.description, _story.uri, _story.storyType, _story.media, _story.scrapedDate, _story.hash, _story.articleText, _story.canSummarize]);
          }

          // add notification job
          // ObjectQty, Data, JobDate, JobType, Processed, Status
          await db.run(insertNotification, [filteredStories.length, JSON.stringify(filteredStories), scrapedDate, "NEWS", false, "NOT_PROCESSED"]);
          const jobEndDate = moment().tz("America/Puerto_Rico").format();
          await db.run(updateScrapingJobQuery, [filteredStories.length, true, "PROCESSED", jobEndDate, scrapingJobId]);
          insertComplete = true;
        } catch (error) {
          console.log(`Insert attempt ${insertAttempts} exception: ${error}`);
        }
    }
    db.close();
    return insertComplete;
  });

