  ipcMain.removeHandler('save-scraped-laws');
  ipcMain.handle('save-scraped-laws', async (event, args) => {
    const db = new ImparcialDb();
    const laws: any[] = args[0];
    const administrationId = args[1] as number;
    const scrapingJobState = args[2] as ScrapingJobState;
    let scrapingJobId = -1;
    let scrapedDate = '';

    if(scrapingJobState && scrapingJobState.ScrapingJobId > 0) {
      scrapingJobId = scrapingJobState.ScrapingJobId;
      scrapedDate = scrapingJobState.ScrapingDate;
    }
    else {
      // query last scraping job for laws
      const scrapingJob = await db.get("SELECT ScrapeJobId, JobStartDate from ScrapingJob WHERE JobType = 'LAW_SCRAPER' AND Processed = 0 AND Status = 'NOT_PROCESSED' LIMIT 1;");
      if(scrapingJob) {
        scrapingJobId = scrapingJob.ScrapeJobId;
        scrapedDate = scrapingJob.JobStartDate;
      }
      else {
        throw new Error("No scraping job found for law scraper");
      }
    }

    const lookupLegislation = "SELECT value from json_each(?) WHERE value not in (SELECT Hash FROM Legislation);";
    const addLegislationQuery = "INSERT INTO Legislation(Number, FiledDate, Title, Author, CoAuthor, Uri, Committe, AdministrationId, LastEvent, ScrapedDate, Hash) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);";
    // const lastInsert = "SELECT last_insert_rowid();";
    const insertEventsQuery = "INSERT OR IGNORE INTO LegislationEvent(Title, Description, Uri, Document, DocType, ScrapedDate, Hash, LegislationIdFk, CreatedDate) VALUES (?,?,?,?,?,?,?,?,?);";
    const addNotifcationQuery = "INSERT INTO NotificationJob (ObjectQty, Data, JobDate, JobType, Processed, Status) VALUES (?, ?, ?, ?, ?, ?);";
    const updateScrapingJobQuery = "UPDATE ScrapingJob SET ObjectQty = ?, Processed = ?, Status = ?, JobEndDate = ? WHERE ScrapeJobId = ?;";

    const getLegislationEvent = async (url: string, legislationId: number) => {
      const browser = await chromium.launch();  // Or 'firefox' or 'webkit'.
      const page = await browser.newPage();
      await page.goto(url, {timeout: 24000, waitUntil: 'load'});
      const html = await page.content();
      
      const $ = cheerio.load(html);
      // divide-y divide-gray-100

      const listItems = $('ul.divide-y.divide-gray-100').find('li');
      let body = "";
      let workingBody = "";
      let eventTitle = "";
      // let paragraphs = [];
      let hash = "";
      let events = [];
      for(let i=0; i < listItems.length; i++) {
        eventTitle = $(listItems[i]).find('h2').text().trim();
        if(eventTitle = "Radicado") {
          const paragraphs = $(listItems[i]).find('p');
          for(let ii=0; ii < paragraphs.length; ii++) {
            workingBody = $(paragraphs[ii]).text().trim();
            if(!workingBody.includes("doc") && !workingBody.includes("docx") && !workingBody.includes("pdf")) {
              body += workingBody;
              body += "\n";
            }
          }

          const msgBuffer = new TextEncoder().encode(administrationId.toString() + eventTitle + body + legislationId.toString());
          const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
          const hashArray = Array.from(new Uint8Array(hashBuffer));
          hash = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');

          // Title, Description, Uri, Document, DocType, ScrapedDate, Hash, LegislationIdFk, CreatedDate
          const event: any = {
            Title: eventTitle,
            Description: body,
            Uri: '',
            Document: undefined,
            DocType: '',
            ScrapedDate: scrapedDate,
            Hash: hash,
            LegislationIdFk: -1,
            CreatedDate: ''
          };

          if($(listItems[i]).find('a').length > 0) {
            const uri = "https://sutra.oslpr.org" + $(listItems[i]).find('a').attr('href');
            const docType = $(listItems[i]).find('a').attr('href').split('.').at(-1);
            // download doc
            try {
              const response = await fetch(uri);
              if(response.ok) {
                // Load the entire file into memory as an ArrayBuffer
                const arrayBuffer = await response.arrayBuffer();
                const buffer = Buffer.from(arrayBuffer);
                event.Document = buffer;
                event.Uri = uri;
                event.DocType = docType;
              }
            } catch (error) {
              console.log(`Error downloading project: ${error}`);
            }
          }

          events.push(event);
          break;
        }
      }
      
      return events;
    }


    // get hashes for lookup
    const hashes = laws.map((law) => law.Hash);
    // console.log({hashes});
    const newLegislationHashes = await db.all(lookupLegislation, [JSON.stringify(hashes)]);
    // console.log({newLegislationHashes});
    let newLegislation: any[] = [];

    if(newLegislationHashes) {
      for(let i=0; i < newLegislationHashes.length; i++) {
        for (let j=0; j < laws.length; j++) {
          if(newLegislationHashes[i].value == laws[j].Hash) {
            // law is new, add
            newLegislation.push(laws[j]);
            break;
          }
        }
      }
    }

    let legislationId = -1;
    let currentLegislation = null;

    try {

      for(let ii=0; ii < newLegislation.length; ii++) {
        // insert legislation
        currentLegislation = newLegislation[ii];
        await db.run(addLegislationQuery, [newLegislation[ii].Number, newLegislation[ii].FiledDate, newLegislation[ii].Title, newLegislation[ii].Author,
          newLegislation[ii].CoAuthor, newLegislation[ii].Uri, newLegislation[ii].Committe, newLegislation[ii].AdministrationId, newLegislation[ii].LastEvent,
          newLegislation[ii].ScrapedDate, newLegislation[ii].Hash]);
        // get lastId
        legislationId = db.getLastId();
        newLegislation[ii].LegislationId = legislationId;
        
        // get Radicado event
        
        // if(legislationId > 0) {
        //   events = await getLegislationEvent(newLegislation[ii].Uri, legislationId);
        //   // insert events
        //   for(let iii=0; iii < events.length; iii++) {
        //     lastEventObj = events[iii];
        //     // LegislationEvent(Title, Description, Uri, Document, DocType, ScrapedDate, Hash, LegislationIdFk, CreatedDate
        //     await db.run(insertEventsQuery, [events[iii].Title, events[iii].Description, events[iii].Uri, events[iii].Document, events[iii].DocType, scrapedDate, events[iii].Hash, legislationId, moment().tz("America/Puerto_Rico").format()]);
        //   }
        // }
      }

      if(newLegislation.length > 0) {
        const notificationData = JSON.stringify(newLegislation);
        // ObjectQty, Data, JobDate, JobType, Processed, Status
        await db.run(addNotifcationQuery, [newLegislation.length, notificationData, moment().tz("America/Puerto_Rico").format(), "LEGISLATION", false, "NOT_PROCESSED"]);
      }
      
      await db.run(updateScrapingJobQuery, [newLegislation.length, true, "PROCESSED", moment().tz("America/Puerto_Rico").format(), scrapingJobId]);

      return true;

    } catch (error) {
      console.log(`Error saving laws: ${error}`);
      console.log(`Last attempted law insert: ${JSON.stringify(currentLegislation)}`);
      return false;
    } finally {
      db.close();
    }
    
  });
  
